class Solution {
public:
    int shipWithinDays(vector<int>& weights, int days) {
        int left = *max_element(weights.begin(), weights.end());
        int right = accumulate(weights.begin(), weights.end(), 0);
        while (left < right) {
            int mid = left + (right - left) / 2;
            int count = 1, curr = 0;
            for (int w : weights) {
                if (curr + w > mid) {
                    count++;
                    curr = 0;
                }
                curr += w;
            }
            if (count > days) left = mid + 1;
            else right = mid;
        }
        return left;
    }
};
